```plantuml
@startuml
package "Modulo-matrícula/Informática" <<Rectangle>> {
    class Matrícula {
        -cliente: Client
        -tempo: Int
        -quadra: Turma
    }

    class Aluno {
        -id: Int
        -nome: String
        -locaçao: List<Matrícula>
    }

    class controleNúmeroMatrícula {
        -quantidade: Int
    }

    class Curso {
        -nome: String
        -quadra: List<Turma>
    }

    class Turma {
        -numero: Int
        -aluguel: Matrícula
        -ginasio: Curso
    }

    Matrícula "0..*" *-right- "1" Aluno : < composição
    Matrícula "1..*" *-- "1" Turma : > composição
    Curso "1..*" -right-* "1" Turma : > composição
    Turma .up.|> controleNúmeroMatrícula
}
@enduml
```
